code.cpp:
vector<int> findDisappearedNumbers(vector<int>& nums){
    for(int num:nums){
        int index=abs(num)-1;
        if(nums[index]>0)
            nums[index]*=-1;
    }

    vector<int> ans;
    for(int i=0;i<nums.size();i++)
        if(nums[i]>0)
            ans.push_back(i+1);

    return ans;
}

